import { isUndefined } from 'lodash-es';

import { settingsObjectsClient } from '@dynatrace-sdk/client-classic-environment-v2';

type GeoSettings = {
  displayWorldmap?: boolean;
};

let cachedResponse: boolean | undefined;

export const fetchClientConfigMapEnabled = async (): Promise<boolean> => {
  if (isUndefined(cachedResponse)) {
    cachedResponse = true; // enabled by default

    try {
      const settings = await settingsObjectsClient.getSettingsObjects({
        schemaIds: 'builtin:geo-settings',
        scopes: 'environment',
        fields: 'value',
      });

      if (settings) {
        const displayWorldmapItem = settings.items.find(
          (item) => (item.value as GeoSettings)?.displayWorldmap !== undefined,
        );

        if (!isUndefined(displayWorldmapItem?.value)) {
          cachedResponse = (displayWorldmapItem.value as GeoSettings)
            .displayWorldmap as boolean;
        }
      }
    } catch {
      // in case there's an error, we fall back to default
      cachedResponse = true;
    }
  }

  return cachedResponse;
};
